mapper.update:
update evaluation_period
set period_status = #{periodStatus}
where period_id = #{periodId}
and com_id = #{comId}

mapper.select:
select period_id, com_id, eval_year, eval_term, title, period_status, TO_CHAR(start_date, 'YYYY-MM-DD') AS start_date, TO_CHAR(end_date, 'YYYY-MM-DD') AS end_date, TO_CHAR(created_at, 'YYYY-MM-DD') AS created_at, TO_CHAR(updated_at, 'YYYY-MM-DD') AS updated_at from evaluation_period
com_id = #{comId}
and eval_year = #{evalYear}
and eval_term = #{evalTerm}
and period_status = #{periodStatus}
order by eval_year DESC, CASE eval_term WHEN 'ANNUAL' THEN 3 WHEN 'H2' THEN 2 WHEN 'H1' THEN 1 END DESC, period_id DESC
